import { z } from 'zod';

const DomainInfoSchema = z.object({
  domain: z.string(),
  type: z.string().optional(),
  confidence: z.string(),
});

const DomainSourceEntrySchema = z.object({
  domains: z.array(DomainInfoSchema),
  notes: z.string(),
});

export const DomainSourcesSchema = z.record(DomainSourceEntrySchema);

export type DomainSources = z.infer<typeof DomainSourcesSchema>;

export const validateDomainSources = (sources: unknown): DomainSources => {
  return DomainSourcesSchema.parse(sources);
};

