/**
 * Domain lookup resolver
 *
 * Loads config/domain-sources.json and transforms it from:
 *   { "financial": { "domains": [{ "domain": "chase.com", "confidence": "high", "type": "bank" }] } }
 *
 * To domainLookup format:
 *   { "financial": {
 *       "highConfidence": [{ "domain": "chase.com", "type": "bank" }],
 *       "mediumConfidence": [...],
 *       "lowConfidence": [...]
 *     }
 *   }
 *
 * Used by ClassificationPipeline for domain-based hard assertions and strong indicators.
 */

import * as fs from 'fs';
import * as path from 'path';

/**
 * Domain entry in the transformed lookup structure
 */
export interface DomainEntry {
  domain: string;
  type?: string;
}

/**
 * Category-specific domain lookup grouped by confidence tier
 */
export interface CategoryDomainLookup {
  highConfidence: DomainEntry[];
  mediumConfidence: DomainEntry[];
  lowConfidence: DomainEntry[];
}

/**
 * Complete domain lookup structure for all categories
 */
export type DomainLookup = Record<string, CategoryDomainLookup>;

/**
 * Source domain entry from domain-sources.json
 */
interface SourceDomainEntry {
  domain: string;
  confidence: 'high' | 'medium' | 'low';
  type?: string;
}

/**
 * Source category structure from domain-sources.json
 */
interface SourceCategory {
  domains: SourceDomainEntry[];
  notes?: string;
}

/**
 * Source domain-sources.json structure
 */
interface SourceDomainConfig {
  [categoryName: string]: SourceCategory | { schema_version?: number; generated?: string };
}

/**
 * Load and transform domain-sources.json into domainLookup format
 *
 * @returns Domain lookup grouped by category and confidence tier
 *
 * @example
 * const lookup = loadDomainLookup();
 * const financialHighConf = lookup.financial.highConfidence;
 * // => [{ domain: "chase.com", type: "bank" }, ...]
 */
export function loadDomainLookup(): DomainLookup {
  try {
    // Locate domain-sources.json in config/ directory
    const configPath = path.resolve(__dirname, '../../../../config/domain-sources.json');

    // Check if file exists
    if (!fs.existsSync(configPath)) {
      console.warn(
        `[domain-resolver] config/domain-sources.json not found at ${configPath}. Using empty domain lookup.`
      );
      return {};
    }

    // Read and parse domain-sources.json
    const fileContent = fs.readFileSync(configPath, 'utf-8');
    const sourceConfig: SourceDomainConfig = JSON.parse(fileContent);

    // Transform to domainLookup format
    const domainLookup: DomainLookup = {};

    for (const [categoryName, categoryData] of Object.entries(sourceConfig)) {
      // Skip metadata entry (not a category)
      if (categoryName === 'metadata') {
        continue;
      }

      // Skip if not a valid category structure
      if (!categoryData || typeof categoryData !== 'object' || !('domains' in categoryData)) {
        console.warn(`[domain-resolver] Skipping invalid category: ${categoryName}`);
        continue;
      }

      const category = categoryData as SourceCategory;

      // Initialize confidence tiers
      const categoryLookup: CategoryDomainLookup = {
        highConfidence: [],
        mediumConfidence: [],
        lowConfidence: [],
      };

      // Group domains by confidence tier
      for (const entry of category.domains) {
        // Validate entry structure
        if (!entry || typeof entry !== 'object' || !entry.domain || !entry.confidence) {
          console.warn(`[domain-resolver] Skipping invalid domain entry in category ${categoryName}:`, entry);
          continue;
        }

        // Transform: remove confidence property, keep domain and type
        const transformedEntry: DomainEntry = {
          domain: entry.domain,
        };

        // Only include type if present
        if (entry.type) {
          transformedEntry.type = entry.type;
        }

        // Add to appropriate confidence tier
        switch (entry.confidence) {
          case 'high':
            categoryLookup.highConfidence.push(transformedEntry);
            break;
          case 'medium':
            categoryLookup.mediumConfidence.push(transformedEntry);
            break;
          case 'low':
            categoryLookup.lowConfidence.push(transformedEntry);
            break;
          default:
            console.warn(
              `[domain-resolver] Unknown confidence level "${entry.confidence}" for domain ${entry.domain} in category ${categoryName}`
            );
        }
      }

      domainLookup[categoryName] = categoryLookup;
    }

    console.log(`[domain-resolver] Loaded domain lookup for ${Object.keys(domainLookup).length} categories`);
    return domainLookup;
  } catch (error) {
    // Graceful degradation: log error and return empty lookup
    console.error('[domain-resolver] Error loading domain-sources.json:', error);
    console.warn('[domain-resolver] Using empty domain lookup due to error');
    return {};
  }
}

